import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Button } from '../../components/ui/button';
import { Input } from '../../components/ui/input';
import { Badge } from '../../components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '../../components/ui/avatar';
import { 
  Search, Star, MapPin, Clock, DollarSign, Stethoscope, Users,
  X, User, Mail, Phone, Heart, AlertCircle
} from 'lucide-react';
import { 
  searchDoctors, mockDoctors, mockPatients, mockAppointments, getActivePatients 
} from '../../services/mockData';
import LoadingSpinner from '../../components/ui/LoadingSpinner';

// Configuration based on user role
const ROLE_CONFIG = {
  patient: {
    title: 'Find Your Doctor',
    subtitle: 'Search and book appointments with top-rated doctors',
    placeholder: 'Search doctors by name, specialization, or hospital...',
    tips: [
      'Search by doctor name (e.g., "Dr. Sarah Johnson")',
      'Search by specialization (e.g., "Cardiology", "Pediatrics")', 
      'Search by hospital or degree',
      'Click on any doctor to book an appointment'
    ]
  },
  doctor: {
    title: 'Search Your Patients',
    subtitle: 'Find patients by name, email, or medical condition',
    placeholder: 'Search patients by name, email, or medical condition...',
    tips: [
      'Search by patient name (e.g., "John Smith")',
      'Search by email address',
      'Search by medical condition (e.g., "Hypertension", "Diabetes")',
      'Click on any patient to view their records'
    ]
  },
  admin: {
    title: 'Universal Search',
    subtitle: 'Search across all system data',
    placeholder: 'Search doctors, patients, or system data...',
    tips: [
      'Search for doctors by name or specialization',
      'Search for patients by name or email',
      'Search across all system data',
      'Click on any result to view details'
    ]
  }
};

// Utility functions
const getSpecializationColor = (specialization) => {
  const colors = {
    'Cardiology': 'bg-red-100 text-red-800',
    'Dermatology': 'bg-green-100 text-green-800',
    'Family Medicine': 'bg-blue-100 text-blue-800',
    'Orthopedics': 'bg-purple-100 text-purple-800',
    'Pediatrics': 'bg-pink-100 text-pink-800',
    'Neurology': 'bg-indigo-100 text-indigo-800',
  };
  return colors[specialization] || 'bg-gray-100 text-gray-800';
};

const calculateAge = (dateOfBirth) => {
  if (!dateOfBirth) return 'N/A';
  const today = new Date();
  const birthDate = new Date(dateOfBirth);
  let age = today.getFullYear() - birthDate.getFullYear();
  const monthDiff = today.getMonth() - birthDate.getMonth();
  
  if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
    age--;
  }
  
  return age;
};

const renderStars = (rating) => {
  const stars = [];
  const fullStars = Math.floor(rating);
  const hasHalfStar = rating % 1 !== 0;

  for (let i = 0; i < fullStars; i++) {
    stars.push(<Star key={i} className="w-4 h-4 fill-yellow-400 text-yellow-400" />);
  }

  if (hasHalfStar) {
    stars.push(<Star key="half" className="w-4 h-4 fill-yellow-400/50 text-yellow-400" />);
  }

  const remainingStars = 5 - Math.ceil(rating);
  for (let i = 0; i < remainingStars; i++) {
    stars.push(<Star key={`empty-${i}`} className="w-4 h-4 text-gray-300" />);
  }

  return stars;
};

// Result components
const DoctorResult = ({ result, onSelect }) => (
  <Card
    className="hover:shadow-md transition-all cursor-pointer border-2 hover:border-blue-200 bg-white"
    onClick={() => onSelect(result)}
  >
    <CardContent className="p-4">
      <div className="flex items-start gap-4">
        <Avatar className="w-16 h-16 ring-2 ring-blue-100">
          <AvatarImage src={result.avatar} alt={result.name} />
          <AvatarFallback className="bg-blue-100 text-blue-600 text-lg font-semibold">
            {result.name.split(' ').map(n => n[0]).join('')}
          </AvatarFallback>
        </Avatar>

        <div className="flex-1 space-y-2">
          <div className="flex items-start justify-between">
            <div>
              <h3 className="text-lg font-semibold text-gray-900">{result.name}</h3>
              <div className="flex items-center gap-2 mb-1">
                <Badge className={getSpecializationColor(result.specialization)}>
                  {result.specialization}
                </Badge>
                <div className="flex items-center gap-1">
                  {(result.degrees || []).map((degree, index) => (
                    <Badge key={index} variant="outline" className="text-xs">
                      {degree}
                    </Badge>
                  ))}
                </div>
              </div>
            </div>

            <div className="text-right">
              <div className="flex items-center gap-1 mb-1">
                {renderStars(result.rating)}
                <span className="ml-1 text-sm font-medium">{result.rating}</span>
              </div>
              <p className="text-xs text-gray-500">({result.reviews} reviews)</p>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm text-gray-600">
            <div className="flex items-center gap-1">
              <Stethoscope className="w-4 h-4" />
              <span>{result.experience} years exp.</span>
            </div>
            <div className="flex items-center gap-1">
              <MapPin className="w-4 h-4" />
              <span className="truncate">{result.hospital}</span>
            </div>
            <div className="flex items-center gap-1">
              <DollarSign className="w-4 h-4" />
              <span>${result.consultationFee}</span>
            </div>
            <div className="flex items-center gap-1">
              <Clock className="w-4 h-4" />
              <span>Available today</span>
            </div>
          </div>
        </div>
      </div>
    </CardContent>
  </Card>
);

const PatientResult = ({ result, onSelect }) => (
  <Card
    className="hover:shadow-md transition-all cursor-pointer border-2 hover:border-green-200 bg-white"
    onClick={() => onSelect(result)}
  >
    <CardContent className="p-4">
      <div className="flex items-start gap-4">
        <Avatar className="w-16 h-16 ring-2 ring-green-100">
          <AvatarImage src={result.avatar} alt={result.name} />
          <AvatarFallback className="bg-green-100 text-green-600 text-lg font-semibold">
            {(result.name || 'Unknown').split(' ').map(n => n[0]).join('')}
          </AvatarFallback>
        </Avatar>

        <div className="flex-1 space-y-2">
          <div className="flex items-start justify-between">
            <div>
              <h3 className="text-lg font-semibold text-gray-900">
                {result.name || 'Unknown Patient'}
              </h3>
              <div className="flex items-center gap-2 mb-1">
                <Badge variant="outline">
                  {calculateAge(result.dateOfBirth)} years old
                </Badge>
                <Badge variant="outline">
                  {result.gender || 'N/A'}
                </Badge>
              </div>
            </div>

            <div className="text-right">
              <div className="flex items-center gap-1">
                <Heart className="w-4 h-4 text-red-500" />
                <span className="text-sm font-medium">Patient</span>
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm text-gray-600">
            <div className="flex items-center gap-1">
              <Mail className="w-4 h-4" />
              <span className="truncate">{result.email}</span>
            </div>
            <div className="flex items-center gap-1">
              <Phone className="w-4 h-4" />
              <span>{result.phone}</span>
            </div>
          </div>

          {/* Medical History */}
          {(result.medicalHistory || []).length > 0 && (
            <div className="space-y-1">
              <p className="text-xs font-medium text-gray-700">Medical History:</p>
              <div className="flex flex-wrap gap-1">
                {(result.medicalHistory || []).slice(0, 3).map((condition, index) => (
                  <Badge 
                    key={index} 
                    variant="outline" 
                    className={`text-xs ${result.matchedCondition === condition ? 'bg-yellow-100 border-yellow-300' : ''}`}
                  >
                    {condition}
                  </Badge>
                ))}
                {(result.medicalHistory || []).length > 3 && (
                  <Badge variant="outline" className="text-xs">
                    +{(result.medicalHistory || []).length - 3} more
                  </Badge>
                )}
              </div>
            </div>
          )}

          {/* Matched condition highlight */}
          {result.matchedCondition && (
            <div className="flex items-center gap-1 text-sm text-yellow-700 bg-yellow-50 p-2 rounded">
              <AlertCircle className="w-4 h-4" />
              <span>Matches condition: <strong>{result.matchedCondition}</strong></span>
            </div>
          )}
        </div>
      </div>
    </CardContent>
  </Card>
);

const UniversalSearch = ({ onClose, initialQuery = '' }) => {
  const [query, setQuery] = useState(initialQuery);
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const { user } = useAuth();
  
  const config = ROLE_CONFIG[user?.role] || ROLE_CONFIG.admin;

  // Search function that adapts to user role
  const searchByRole = useCallback(async (searchQuery) => {
    if (!searchQuery.trim()) {
      setResults([]);
      return;
    }

    setLoading(true);
    try {
      let searchResults = [];

      if (user?.role === 'patient') {
        // Patient searches for doctors
        searchResults = await searchDoctors(searchQuery);
        searchResults = searchResults.map(doctor => ({ ...doctor, type: 'doctor' }));
      } else if (user?.role === 'doctor') {
        // Doctor searches for patients and medical conditions
        const doctorId = user?.id || 'doc-1';
        const activePatients = await getActivePatients(doctorId);
        
        // Search patients by name and medical conditions
        const patientResults = activePatients.filter(patient => 
          patient.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
          patient.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
          (patient.medicalHistory || []).some(condition =>
            condition.toLowerCase().includes(searchQuery.toLowerCase())
          )
        ).map(patient => {
          const matchedCondition = (patient.medicalHistory || []).find(condition =>
            condition.toLowerCase().includes(searchQuery.toLowerCase())
          );
          return { ...patient, type: 'patient', matchedCondition };
        });

        // Remove duplicates
        searchResults = patientResults.filter((result, index, self) =>
          index === self.findIndex(r => r.id === result.id)
        );
      } else if (user?.role === 'admin') {
        // Admin can search everything
        const doctorResults = await searchDoctors(searchQuery);
        const patientResults = mockPatients.filter(patient =>
          patient.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
          patient.email.toLowerCase().includes(searchQuery.toLowerCase())
        );

        searchResults = [
          ...doctorResults.map(doctor => ({ ...doctor, type: 'doctor' })),
          ...patientResults.map(patient => ({ ...patient, type: 'patient' }))
        ];
      }

      setResults(searchResults);
    } catch (error) {
      console.error('Search error:', error);
      setResults([]);
    } finally {
      setLoading(false);
    }
  }, [user]);

  // Debounced search effect
  useEffect(() => {
    const timeoutId = setTimeout(() => {
      searchByRole(query);
    }, 300);

    return () => clearTimeout(timeoutId);
  }, [query, searchByRole]);

  // Handle selection based on result type
  const handleResultSelect = (result) => {
    const routes = {
      patient: {
        doctor: `/app/patient/appointments/book?doctorId=${result.id}&fromSearch=true`
      },
      doctor: {
        patient: `/app/doctor/patients/${result.id}`
      },
      admin: {
        doctor: `/app/admin/doctors/${result.id}`,
        patient: `/app/admin/patients/${result.id}`
      }
    };

    const route = routes[user?.role]?.[result.type];
    if (route) {
      navigate(route);
      onClose?.();
    }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <Card className="w-full max-w-6xl max-h-[95vh] overflow-hidden bg-white shadow-2xl border border-gray-200 rounded-xl">
        <CardHeader className="flex flex-row items-center justify-between bg-white border-b border-gray-100">
          <div>
            <CardTitle className="flex items-center gap-2 text-gray-900">
              <Search className="w-5 h-5 text-blue-600" />
              {config.title}
            </CardTitle>
            <p className="text-sm text-gray-600 mt-1">{config.subtitle}</p>
          </div>
          {onClose && (
            <Button variant="ghost" size="sm" onClick={onClose}>
              <X className="w-5 h-5" />
            </Button>
          )}
        </CardHeader>

        <CardContent className="space-y-4 bg-white">
          {/* Search Input */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
            <Input
              placeholder={config.placeholder}
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="pl-10 pr-4 bg-white border border-gray-300 text-gray-900 placeholder:text-gray-500 focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
              autoFocus
            />
          </div>

          {/* Main Content Area */}
          <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
            {/* Results */}
            <div className="lg:col-span-3">
              <div className="space-y-4 max-h-[500px] overflow-y-auto bg-gray-50 p-3 rounded-lg border border-gray-200">
                {loading ? (
                  <div className="flex items-center justify-center py-8">
                    <LoadingSpinner size="md" />
                  </div>
                ) : results.length === 0 ? (
                  <div className="text-center py-8 text-gray-500 bg-white rounded-lg border border-gray-200 mx-2">
                    {query ? 'No results found matching your search.' : 'Start typing to search...'}
                  </div>
                ) : (
                  results.map((result) =>
                    result.type === 'doctor' ? (
                      <DoctorResult key={result.id} result={result} onSelect={handleResultSelect} />
                    ) : (
                      <PatientResult key={result.id} result={result} onSelect={handleResultSelect} />
                    )
                  )
                )}
              </div>
            </div>

            {/* Search Tips Sidebar */}
            <div className="lg:col-span-1 space-y-4">
              <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 sticky top-0">
                <h4 className="text-sm font-medium text-blue-900 mb-3 flex items-center gap-2">
                  <Search className="w-4 h-4" />
                  Search Tips
                </h4>
                <ul className="text-xs text-blue-800 space-y-2">
                  {config.tips.map((tip, index) => (
                    <li key={index} className="flex items-start gap-2">
                      <span className="text-blue-600 mt-0.5">•</span>
                      <span>{tip}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default UniversalSearch;